type sourceIcons map[string]*sourceIcon

type sourceIcon struct {
	Source string
	Icon   fyne.Resource
}

func newSourceIcon(source string, icon fyne.Resource) *sourceIcon {
	return &sourceIcon{Source: source, Icon: icon}
}

var SourceIcons sourceIcons

func init() {
	SourceIcons = make(map[string]*sourceIcon)
	SourceIcons[consts.SourceBilibili] = newSourceIcon(consts.SourceBilibili, BilibiliIcon)
	SourceIcons[consts.SourceYoutube] = newSourceIcon(consts.SourceYoutube, YoutubeIcon)
	SourceIcons[consts.SourceTwitter] = newSourceIcon(consts.SourceTwitter, XIcon)
	SourceIcons[consts.SourceTencent] = newSourceIcon(consts.SourceTencent, TencentVideoIcon)
	SourceIcons[consts.SourceDouyin] = newSourceIcon(consts.SourceDouyin, DouyinIcon)
	SourceIcons[consts.SourceTiktok] = newSourceIcon(consts.SourceTiktok, TiktokIcon)
	SourceIcons[consts.SourceFacebook] = newSourceIcon(consts.SourceFacebook, FacebookIcon)
	SourceIcons[consts.SourceInstagram] = newSourceIcon(consts.SourceInstagram, InstagramIcon)
	SourceIcons[consts.SourceYouku] = newSourceIcon(consts.SourceYouku, YoukuIcon)
	SourceIcons[consts.SourceXiaohongshu] = newSourceIcon(consts.SourceXiaohongshu, XiaohongshuIcon)
	SourceIcons[consts.SourceVimeo] = newSourceIcon(consts.SourceVimeo, VimeoIcon)
	SourceIcons[consts.SourceTwitch] = newSourceIcon(consts.SourceTwitch, TwitchIcon)
	SourceIcons[consts.SourceReddit] = newSourceIcon(consts.SourceReddit, RedditIcon)
	SourceIcons[consts.SourceKuaishou] = newSourceIcon(consts.SourceKuaishou, KuaishouIcon)
	SourceIcons[consts.SourceIxigua] = newSourceIcon(consts.SourceIxigua, IxiguaIcon)
	SourceIcons[consts.SourceIqiyi] = newSourceIcon(consts.SourceIqiyi, IqiyiIcon)
}

func (si sourceIcons) Get(source string) fyne.Resource {
	if icon, ok := si[source]; ok {
		return icon.Icon
	}
	return nil
}
